const config = {
    "previewFeatures": [],
    "clientVersion": "7.8.0",
    "engineVersion": "3c6e192761c0362d496ed980de936e2f3cebcd3a",
    "activeProvider": "postgresql",
    "inlineSchema": "// apps/api/prisma/schema.prisma\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// -----------------------------------------------------------------------------\n// USERS & AUTH\n// -----------------------------------------------------------------------------\n\nenum Role {\n  SUPER_ADMIN\n  ADMIN\n  VENDOR\n  DELIVERY_PARTNER\n  SUPPORT\n  CUSTOMER\n}\n\nmodel User {\n  id           String   @id @default(uuid())\n  email        String   @unique\n  phone        String?  @unique\n  passwordHash String\n  name         String?\n  role         Role     @default(CUSTOMER)\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n  isActive     Boolean  @default(true)\n\n  addresses       Address[]\n  orders          Order[]\n  reviews         Review[]\n  reminders       Reminder[]\n  notifications   Notification[]\n  auditLogs       AuditLog[]\n  deliveryPartner DeliveryPartner?\n  vendor          Vendor?\n}\n\nmodel Address {\n  id           String        @id @default(uuid())\n  userId       String\n  user         User          @relation(fields: [userId], references: [id], onDelete: Cascade)\n  type         String        @default(\"HOME\") // HOME, WORK, etc.\n  name         String\n  phone        String\n  addressLine  String\n  area         String\n  city         String\n  pincode      String\n  state        String\n  country      String        @default(\"India\")\n  isDefault    Boolean       @default(false)\n  createdAt    DateTime      @default(now())\n  updatedAt    DateTime      @updatedAt\n  DeliveryZone DeliveryZone? @relation(fields: [pincode], references: [pincode])\n\n  @@index([userId])\n}\n\n// -----------------------------------------------------------------------------\n// CATALOG: Categories, Occasions, Relationships\n// -----------------------------------------------------------------------------\n\nmodel Category {\n  id          String   @id @default(uuid())\n  name        String   @unique\n  slug        String   @unique\n  description String?\n  imageUrl    String?\n  isActive    Boolean  @default(true)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  products ProductCategory[]\n}\n\nmodel Occasion {\n  id       String  @id @default(uuid())\n  name     String  @unique\n  slug     String  @unique\n  imageUrl String?\n  isActive Boolean @default(true)\n\n  products ProductOccasion[]\n}\n\nmodel Relationship {\n  id       String  @id @default(uuid())\n  name     String  @unique\n  slug     String  @unique\n  imageUrl String?\n  isActive Boolean @default(true)\n\n  products ProductRelationship[]\n}\n\n// -----------------------------------------------------------------------------\n// PRODUCTS & INVENTORY\n// -----------------------------------------------------------------------------\n\nmodel Product {\n  id               String   @id @default(uuid())\n  name             String\n  slug             String   @unique\n  description      String?\n  whatsInside      String?\n  price            Float\n  compareAtPrice   Float?\n  isActive         Boolean  @default(true)\n  stock            Int      @default(0)\n  deliveryEstimate String?\n  sameDayAvailable Boolean  @default(false)\n  isPersonalizable Boolean  @default(false)\n  tags             String[] // Simple array of strings\n  createdAt        DateTime @default(now())\n  updatedAt        DateTime @updatedAt\n\n  images         ProductImage[]\n  categories     ProductCategory[]\n  occasions      ProductOccasion[]\n  relationships  ProductRelationship[]\n  orderItems     OrderItem[]\n  reviews        Review[]\n  vendorProducts VendorProduct[]\n}\n\nmodel ProductImage {\n  id        String  @id @default(uuid())\n  productId String\n  product   Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n  url       String\n  isPrimary Boolean @default(false)\n  order     Int     @default(0)\n\n  @@index([productId])\n}\n\n// Mapping Tables\nmodel ProductCategory {\n  productId  String\n  categoryId String\n  product    Product  @relation(fields: [productId], references: [id], onDelete: Cascade)\n  category   Category @relation(fields: [categoryId], references: [id], onDelete: Cascade)\n\n  @@id([productId, categoryId])\n}\n\nmodel ProductOccasion {\n  productId  String\n  occasionId String\n  product    Product  @relation(fields: [productId], references: [id], onDelete: Cascade)\n  occasion   Occasion @relation(fields: [occasionId], references: [id], onDelete: Cascade)\n\n  @@id([productId, occasionId])\n}\n\nmodel ProductRelationship {\n  productId      String\n  relationshipId String\n  product        Product      @relation(fields: [productId], references: [id], onDelete: Cascade)\n  relationship   Relationship @relation(fields: [relationshipId], references: [id], onDelete: Cascade)\n\n  @@id([productId, relationshipId])\n}\n\n// -----------------------------------------------------------------------------\n// CART & ORDERS\n// -----------------------------------------------------------------------------\n\nmodel Cart {\n  id        String     @id @default(uuid())\n  userId    String? // Nullable for guest carts\n  session   String?    @unique // Session ID for guest carts\n  items     CartItem[]\n  createdAt DateTime   @default(now())\n  updatedAt DateTime   @updatedAt\n}\n\nmodel CartItem {\n  id          String @id @default(uuid())\n  cartId      String\n  cart        Cart   @relation(fields: [cartId], references: [id], onDelete: Cascade)\n  productId   String\n  quantity    Int    @default(1)\n  variantData Json?\n\n  @@index([cartId])\n}\n\nenum OrderStatus {\n  PLACED\n  PAYMENT_PENDING\n  PAYMENT_CONFIRMED\n  ACCEPTED\n  PREPARING\n  READY_FOR_PICKUP\n  OUT_FOR_DELIVERY\n  DELIVERED\n  CANCELLED\n  REFUNDED\n  FAILED\n}\n\nmodel Order {\n  id          String      @id @default(uuid())\n  orderNumber String      @unique // e.g. CESTO-123456\n  userId      String?\n  user        User?       @relation(fields: [userId], references: [id], onDelete: SetNull)\n  status      OrderStatus @default(PAYMENT_PENDING)\n  totalAmount Float\n  deliveryFee Float       @default(0)\n  discount    Float       @default(0)\n  finalAmount Float\n\n  // Recipient details\n  recipientName   String\n  recipientPhone  String\n  deliveryAddress Json // Snapshot of address\n  deliverySlotId  String?\n  deliverySlot    DeliverySlot? @relation(fields: [deliverySlotId], references: [id], onDelete: SetNull)\n  deliveryDate    DateTime\n  giftMessage     String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  items             OrderItem[]\n  payments          Payment[]\n  refunds           Refund[]\n  deliveryProof     DeliveryProof?\n  vendorId          String?\n  vendor            Vendor?          @relation(fields: [vendorId], references: [id])\n  deliveryPartnerId String?\n  deliveryPartner   DeliveryPartner? @relation(fields: [deliveryPartnerId], references: [id])\n}\n\nmodel OrderItem {\n  id          String  @id @default(uuid())\n  orderId     String\n  order       Order   @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  productId   String\n  product     Product @relation(fields: [productId], references: [id], onDelete: Restrict)\n  quantity    Int\n  priceAt     Float // Price when ordered\n  variantData Json?\n\n  @@index([orderId])\n}\n\n// -----------------------------------------------------------------------------\n// PAYMENTS & REFUNDS\n// -----------------------------------------------------------------------------\n\nenum PaymentStatus {\n  PENDING\n  SUCCESS\n  FAILED\n  REFUNDED\n}\n\nmodel Payment {\n  id                String        @id @default(uuid())\n  orderId           String\n  order             Order         @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  razorpayOrderId   String?       @unique\n  razorpayPaymentId String?       @unique\n  amount            Float\n  status            PaymentStatus @default(PENDING)\n  method            String?\n  createdAt         DateTime      @default(now())\n  updatedAt         DateTime      @updatedAt\n}\n\nmodel Refund {\n  id               String   @id @default(uuid())\n  orderId          String\n  order            Order    @relation(fields: [orderId], references: [id])\n  amount           Float\n  reason           String?\n  status           String   @default(\"PENDING\") // PENDING, PROCESSED, FAILED\n  razorpayRefundId String?  @unique\n  createdAt        DateTime @default(now())\n  updatedAt        DateTime @updatedAt\n}\n\n// -----------------------------------------------------------------------------\n// DELIVERY\n// -----------------------------------------------------------------------------\n\nmodel DeliveryZone {\n  id          String  @id @default(uuid())\n  city        String\n  area        String\n  pincode     String  @unique\n  isActive    Boolean @default(true)\n  minOrder    Float   @default(0)\n  deliveryFee Float   @default(0)\n  expressFee  Float   @default(0)\n  midnightFee Float   @default(0)\n\n  addresses Address[]\n}\n\nmodel DeliverySlot {\n  id        String  @id @default(uuid())\n  label     String // e.g. \"10 AM - 1 PM\"\n  startTime String // \"10:00\"\n  endTime   String // \"13:00\"\n  type      String  @default(\"STANDARD\") // STANDARD, EXPRESS, MIDNIGHT\n  isActive  Boolean @default(true)\n  fee       Float   @default(0)\n\n  orders Order[]\n}\n\nmodel DeliveryPartner {\n  id          String  @id @default(uuid())\n  userId      String  @unique\n  user        User    @relation(fields: [userId], references: [id], onDelete: Cascade)\n  vehicleType String?\n  vehicleNo   String?\n  isActive    Boolean @default(true)\n\n  orders Order[]\n}\n\nmodel DeliveryProof {\n  id         String   @id @default(uuid())\n  orderId    String   @unique\n  order      Order    @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  imageUrl   String\n  notes      String?\n  uploadedAt DateTime @default(now())\n}\n\n// -----------------------------------------------------------------------------\n// VENDORS\n// -----------------------------------------------------------------------------\n\nmodel Vendor {\n  id        String  @id @default(uuid())\n  userId    String  @unique\n  user      User    @relation(fields: [userId], references: [id], onDelete: Cascade)\n  storeName String\n  address   String?\n  isActive  Boolean @default(true)\n\n  products VendorProduct[]\n  orders   Order[]\n}\n\nmodel VendorProduct {\n  vendorId  String\n  productId String\n  vendor    Vendor  @relation(fields: [vendorId], references: [id], onDelete: Cascade)\n  product   Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n  price     Float?\n  stock     Int     @default(0)\n\n  @@id([vendorId, productId])\n}\n\n// -----------------------------------------------------------------------------\n// MARKETING & CUSTOMER SUPPORT\n// -----------------------------------------------------------------------------\n\nmodel Coupon {\n  id            String   @id @default(uuid())\n  code          String   @unique\n  discountType  String // PERCENTAGE, FIXED\n  discountValue Float\n  minOrderValue Float    @default(0)\n  maxDiscount   Float?\n  validFrom     DateTime\n  validUntil    DateTime\n  isActive      Boolean  @default(true)\n  usageLimit    Int?\n  usageCount    Int      @default(0)\n}\n\nmodel Review {\n  id         String   @id @default(uuid())\n  userId     String\n  user       User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  productId  String\n  product    Product  @relation(fields: [productId], references: [id], onDelete: Cascade)\n  rating     Int      @default(5)\n  comment    String?\n  isApproved Boolean  @default(true)\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n}\n\nmodel Reminder {\n  id        String   @id @default(uuid())\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  title     String // e.g. \"Mom's Birthday\"\n  date      DateTime\n  relation  String?\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n}\n\nmodel Notification {\n  id        String   @id @default(uuid())\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  title     String\n  message   String\n  isRead    Boolean  @default(false)\n  createdAt DateTime @default(now())\n}\n\nmodel CorporateEnquiry {\n  id          String   @id @default(uuid())\n  companyName String\n  contactName String\n  email       String\n  phone       String\n  budget      Float?\n  message     String\n  status      String   @default(\"NEW\") // NEW, CONTACTED, CLOSED\n  createdAt   DateTime @default(now())\n}\n\n// -----------------------------------------------------------------------------\n// ADMIN LOGS & SETTINGS\n// -----------------------------------------------------------------------------\n\nmodel AuditLog {\n  id        String   @id @default(uuid())\n  userId    String?\n  user      User?    @relation(fields: [userId], references: [id], onDelete: SetNull)\n  action    String // e.g. \"UPDATE_ORDER_STATUS\"\n  entity    String // e.g. \"Order\"\n  entityId  String\n  details   Json?\n  createdAt DateTime @default(now())\n}\n\nmodel AdminSetting {\n  id        String   @id @default(uuid())\n  key       String   @unique\n  value     Json\n  updatedAt DateTime @updatedAt\n}\n",
    "runtimeDataModel": {
        "models": {},
        "enums": {},
        "types": {}
    },
    "parameterizationSchema": {
        "strings": [],
        "graph": ""
    }
};
